#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N,M; scanf("%d %d",&N,&M);
        for(int i=0;i<N;i++){
            int x; scanf("%d",&x);
            printf("%d",x);
            if(i+1<N) printf(" ");
        }
        if(T) printf("\n");
    }
    return 0;
}

