#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); M = int(next(it))
        b = [next(it) for _ in range(N)]
        out_lines.append(' '.join(b))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

